#include<bits/stdc++.h>using namespace std;int n;int a[10005];int b[10005];int c[105];int cnt=0;void dfs(int m,int x){    if(cnt==m){        return ;    }	if(m==x){	    for(int i=0;i<x;i++){	        cout<<b[i]<<" ";	    }	    cout<<'\n';	    cnt++;	    return ;	}	if(x<=1){	    for(int i=1;i<=m;i++){	        if(!c[i]){	            b[x]=i;	            c[i]=1;	            dfs(m,x+1);	            c[i]=0;	        }	    }	}else{	    for(int i=1;i<=m;i++){	        if(!c[i]&&b[x-2]+b[x-1]!=i){	            b[x]=i;	            c[i]=1;	            dfs(m,x+1);	            c[i]=0;	        }	    }	}}int main(){		cin>>n;	for(int i=1;i<=n;i++){		cin>>a[i];		cnt=0;		dfs(a[i],0);	}		return 0;}